// Import necessary libraries
import React from 'react';
import { View, Text, Button } from 'react-native';
import * as PaymentSheet from '@stripe/stripe-react-native';

class PaymentModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      paymentMethod: null,
    };
  }

  createPaymentIntent = async () => {
    const response = await fetch('https://your-backend-api.com/create-payment-intent', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        amount: 1099,
        currency: 'usd',
        payment_method_types: ['card'],
      }),
    });
    const data = await response.json();
    return data;
  };

  handlePayment = async () => {
    try {
      // Create a PaymentIntent
      const paymentIntent = await this.createPaymentIntent();

      // Configure the PaymentSheet with the client secret
      const result = await PaymentSheet.configure({
        merchantDisplayName: 'Your App Name',
        paymentMethodsConfig: {
          card: {},
        },
      });

      if (result.status === 'completed') {
        // Present the PaymentSheet
        const { error, paymentOption } = await PaymentSheet.present({
          clientSecret: paymentIntent.client_secret,
          merchantDisplayName: 'Your App Name',
        });

        if (error) {
          console.log('Payment failed:', error.message);
        } else {
          // Handle successful payment
          this.setState({ paymentMethod: paymentOption });
          console.log('Payment successful:', paymentOption);
        }
      } else {
        console.log('Configuration failed');
      }
    } catch (error) {
      console.error('Error processing payment:', error);
    }
  };

  render() {
    return (
      <View>
        <Text>React Native Payment Module</Text>
        <Button title="Process Payment" onPress={this.handlePayment} />
      </View>
    );
  }
}

export default PaymentModule;